// src/provider/gitlab.ts
async function run2(repositories, ref, files) {
  const token = process.env.PEW_GITLAB_TOKEN;
  if (!token) {
    throw new Error("Gitlab repositories must supply `env.PEW_GITLAB_TOKEN`");
  }
  const repositoryUri = new URL(repositories[0]);
  const projectName = repositoryUri.pathname.substr(1);
  const api = new Gitlab2({
    host: repositoryUri.origin,
    token
  });
  const commits = await api.Commits.all(projectName, {
    all: false,
    perPage: 1,
    maxPages: 1,
    refName: ref
  });
  if (commits.length !== 1) {
    throw new Error(`Failed to find ref '${ref}'`);
  }
  setSecret(token);
  saveState("gitlabToken", token);
  const commitSha = commits[0].id;
  var repoFiles = [];
  for (const path5 of files) {
    try {
      const { content } = await api.RepositoryFiles.show(
        projectName,
        path5,
        commitSha
      );
      const buffer = Buffer.from(content, "base64");
      repoFiles.push({
        path: path5,
        content: buffer.toString()
      });
    } catch (err) {
      if (err.name !== "GitbeakerRequestError" || err.cause.response.status !== 404) {
        error(`Failed to get file '${path5}'`);
        throw err;
      }
    }
  }
  return {
    token,
    commit: commitSha,
    commitDate: new Date(commits[0].committed_date),
    files: repoFiles
  };
}
async function post3() {
  const token = getState("gitlabToken");
  if (token) {
  }
}
async function create2() {
  return {
    getInfo: run2,
    postAction: post3
  };
}

// src/provider/bitbucket.ts
async function run3(repositories, ref, files) {
  const username = process.env.PEW_BITBUCKET_USERNAME;
  if (!username) {
    throw new Error("Bitbucket repositories must supply `env.PEW_BITBUCKET_USERNAME");
  }
  const password = process.env.PEW_BITBUCKET_PASSWORD;
  if (!password) {
    throw new Error("Bitbucket repositories must supply `env.PEW_BITBUCKET_PASSWORD`");
  }
  setSecret(password);
  saveState("bitbucketPassword", password);
  const token = username + ":" + password;
  const encodedToken = btoa(token);
  setSecret(encodedToken);
  const basicAuth = `Basic ${encodedToken}`;
  const repositoryUri = new URL(repositories[0]);
  const parts = repositoryUri.pathname.split("/");
  if (parts.length !== 3) {
    throw new Error(`Malformed bitbucket repository '${repositories[0]}'`);
  }
  const workspace = parts[1];
  const project = parts[2];
  const commitResponse = await fetch(
    `https://api.bitbucket.org/2.0/repositories/${workspace}/${project}/refs?` + new URLSearchParams({
      q: `name="${ref}"`
    }),
    {
      headers: {
        Authorization: basicAuth
      }
    }
  );
  const commitData = await commitResponse.json();
  if (commitData.type === "error") {
    throw new Error(commitData.error.message);
  }
  var commit = void 0;
  const numCommits = commitData.values ? commitData.values.length : 0;
  if (numCommits === 1) {
    commit = commitData.values[0].target;
  } else if (numCommits > 1) {
    throw new Error(`Multiple commits resovled for ref '${ref}' ?!?!`);
  } else {
    if (!ref.match(/^[a-fA-F0-9]{40}$/)) {
      throw new Error(`Failed to find ref '${ref}'`);
    }
    const commitResponse2 = await fetch(
      `https://api.bitbucket.org/2.0/repositories/${workspace}/${project}/commit/${ref}`,
      {
        headers: {
          Authorization: basicAuth
        }
      }
    );
    const data = await commitResponse2.json();
    if (data.type === "error") {
      throw new Error(data.error.message);
    }
    commit = data;
  }
  const commitSha = commit.hash;
  const commitDate = new Date(commit.date);
  var repoFiles = [];
  for (const path5 of files) {
    const response = await fetch(
      `https://api.bitbucket.org/2.0/repositories/${workspace}/${project}/src/${commitSha}/${path5}`,
      {
        headers: {
          Authorization: basicAuth,
          Accept: "application/json"
        }
      }
    );
    if (response.ok) {
      repoFiles.push({
        path: path5,
        content: await response.text()
      });
    } else {
      if (response.status !== 404) {
        throw new Error(`Failed to fetch '${path5}': ${response.status}: ${response.statusText}`);
      }
    }
  }
  return {
    token,
    commit: commitSha,
    commitDate,
    files: repoFiles
  };
}
